INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('21e7c367-d8ad-527f-bf28-b0928a75f1b8', 'THE DUSIT D2 HOTEL TERROR ATTACK', 'Nairobi', 'January 15, 2019', 'Mass Casualty Incident', 'advanced', 'On January 15, 2019, at approximately 2:30 PM, four armed militants attacked the DusitD2 hotel complex in Nairobi''s Westlands district. The attack began with an explosion in the parking lot, followed by gunfire as the attackers entered the hotel and office complex.', '{"rawText": "CASE STUDY 1: THE DUSIT D2 HOTEL TERROR ATTACK\nNairobi, January 15, 2019\nIncident Background\nOn January 15, 2019, at approximately 2:30 PM, four armed militants attacked the DusitD2 hotel complex in Nairobi''s Westlands district. The attack began with an explosion in the parking lot, followed by gunfire as the attackers entered the hotel and office complex. \n\nIncident Statistics:\n\n21 fatalities (including civilians and security personnel)\n\n28 injured survivors requiring medical evacuation\n\nApproximately 700 people successfully evacuated\n\nDuration of operation: Nearly 20 hours\n\nResponse time: First responders arrived within 10 minutes of the initial explosion\n\nPart 1: Dispatch Information\nYou are an EMT-Basic assigned to an ambulance stationed at Kenyatta National Hospital. The following dispatch message is received:\n\n\"MAJOR INCIDENT - ACTIVE TERROR ATTACK - DUSITD2 HOTEL, 14 RIVERSIDE DRIVE, WESTLANDS.\n\nMultiple casualties reported. Explosion and active gunfire confirmed. Unknown number of injured. Multiple agencies responding including ATPU, GSU, KDF, and Kenya Red Cross.\n\nStage at the designated casualty collection point. Proceed with caution. Security forces are clearing the area. Do not enter the hot zone.\"\n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 1\n1. Scene Size-Up & Safety (Critical First Step):\n\nBased on the dispatch information and your knowledge of active shooter/terror incidents, what are your PRIMARY scene safety concerns?\n\nWhat is the difference between the HOT, WARM, and COLD zones at this type of incident?\n\nWhere should you position your ambulance?\n\nYour Response: (fill in)\n\ntext\nHOT ZONE: ________________________________________________________________\nWARM ZONE: _______________________________________________________________\nCOLD ZONE: ________________________________________________________________\nAmbulance positioning: ____________________________________________________\nPrimary safety concerns: __________________________________________________\n2. BSI & PPE Considerations:\n\nWhat personal protective equipment is essential for this scene?\n\nWhat additional precautions might be needed?\n\nYour Response: (fill in)\n\ntext\nEssential PPE: ___________________________________________________________\nAdditional precautions: ___________________________________________________\n3. Triage & Resource Assessment:\n\nWhat is the estimated number of patients based on dispatch?\n\nWhat additional resources would you request?\n\nHow would you establish communication with command?\n\nYour Response: (fill in)\n\ntext\nEstimated patient count: __________________________________________________\nAdditional resources needed: _____________________________________________\nCommunication plan: ______________________________________________________\nPart 2: Arrival at Scene\nYou arrive at the designated casualty collection point approximately 12 minutes after the first dispatch. Security forces have established a secure perimeter. First patients are being evacuated from the building by police and security personnel. \n\nYour initial scene assessment reveals:\n\nSituation: Active shooter incident with hostages reportedly still inside\n\nSecurity: GSU and ATPU are clearing the building floor by floor\n\nPatients: Approximately 15-20 casualties are being brought to the collection point\n\nTriage set-up: The Kenya Red Cross has established a basic triage area\n\nCommunication: Command post established at the corner of Riverside Drive\n\nYou observe the following patients arriving:\n\nPatient\tAge/Sex\tPresentation\tStatus\nA\t35/M\tGunshot wound to the chest, GCS 14, RR 28, BP 100/70\tConscious, in distress\nB\t42/F\tShrapnel wounds to both legs, profuse bleeding, GCS 15\tConscious, anxious\nC\t60/M\tGunshot wound to the abdomen, GCS 10, RR 32, BP 85/55\tSemi-conscious\nD\t28/M\tPanic attack, no visible injuries, GCS 15\tConscious, hyperventilating\nE\t45/F\tGunshot wound to the head, GCS 3, not breathing\tUnconscious, apneic\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 2\n4. Initial Triage Decision:\nUsing the START (Simple Triage and Rapid Treatment) system, classify each patient:\n\nYour Response: (fill in)\n\ntext\nPatient A (35/M, chest wound, GCS 14, RR 28, BP 100/70):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient B (42/F, shrapnel wounds, GCS 15):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient C (60/M, abdominal wound, GCS 10, RR 32, BP 85/55):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient D (28/M, panic attack, GCS 15):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient E (45/F, head wound, GCS 3, apneic):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n5. Treatment Prioritization:\n\nWhich patient requires immediate intervention?\n\nWhat specific interventions would you perform for each priority patient?\n\nHow would you coordinate with the Kenya Red Cross team?\n\nYour Response: (fill in)\n\ntext\nImmediate intervention patient: __________________________________________\nInterventions: ___________________________________________________________\nCoordination with Red Cross: _____________________________________________\nPart 3: Mass Casualty Management\nThe situation escalates. More patients are being evacuated from the building. Approximately 30 additional casualties are being transported to the collection point. Security forces are reporting that the attack is still ongoing. Your ambulance can transport 2 patients at a time. Additional ambulances are 15-20 minutes away. \n\nNew arrivals include:\n\n5 patients with blast injuries from the initial explosion\n\n3 patients with gunshot wounds to the extremities\n\n8 patients with smoke inhalation\n\n2 pediatric patients (ages 6 and 8) with shrapnel injuries\n\n12 patients with anxiety/panic attacks\n\n1 pregnant woman with signs of labor (initiated by the stress)\n\nThe Kenya Red Cross triage officer requests your assistance in coordinating the evacuation plan.\n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 3\n6. Resource Management & Transport Prioritization:\nDevelop a transport priority plan considering:\n\nAvailable ambulances (your one ALS unit + 2 BLS units on scene)\n\nHospital destination selection (KNH, Aga Khan, Nairobi Hospital)\n\nThe \"Golden Hour\" concept for trauma patients\n\nYour Response: (fill in)\n\ntext\nTransport Priority 1 (Immediate):\nPatient(s): ____________________________________________________________\nDestination: ___________________________________________________________\nRationale: _____________________________________________________________\n\nTransport Priority 2 (Urgent):\nPatient(s): ____________________________________________________________\nDestination: ___________________________________________________________\nRationale: _____________________________________________________________\n\nTransport Priority 3 (Delayed):\nPatient(s): ____________________________________________________________\nDestination: ___________________________________________________________\nRationale: _____________________________________________________________\n7. Special Considerations:\n\nHow do you manage the pediatric patients in a mass casualty setting?\n\nWhat considerations apply to the pregnant patient?\n\nHow would you document this mass casualty incident?\n\nWhat would you tell the receiving hospitals?\n\nYour Response: (fill in)\n\ntext\nPediatric considerations: _______________________________________________\nPregnant patient considerations: ________________________________________\nDocumentation: __________________________________________________________\nHospital notification: __________________________________________________\nPart 4: Lessons Learned - The Dusit Response\nThe response to the Dusit D2 attack was widely praised for its coordination and efficiency compared to the 2013 Westgate Mall attack. \n\nWhat made the Dusit response different?\n\nUnified Command Structure - All units reported to the GSU, eliminating the power struggles seen at Westgate\n\nImproved Intelligence Sharing - The National Counter Terrorism Centre (NCTC) had been strengthened\n\nBetter Equipment and Training - Elite units had received enhanced training with foreign partners\n\nFaster Perimeter Establishment - The area was cordoned off within minutes\n\nRegistration of Evacuees - Survivors were registered to track them and prevent attackers from escaping\n\nMulti-Agency Coordination - KDF, NPS, ATPU, and GSU worked together effectively\n\nSurvival Statistics:\n\nWestgate (2013): 67 deaths, 4 days operation\n\nDusitD2 (2019): 21 deaths, 20 hours operation\n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 4\n8. Reflection & Key Takeaways:\n\nYour Response: (fill in)\n\ntext\n1. What role does EMS play in a mass casualty terror incident?\n______________________________________________________________________\n\n2. How did improved incident command affect patient outcomes?\n______________________________________________________________________\n\n3. What are the challenges of providing care in a hostile environment?\n______________________________________________________________________\n\n4. How does START triage help manage mass casualty incidents?\n______________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nPhase 1\tScene Safety Assessment\t10\tCorrect identification of hot/warm/cold zones\nPhase 1\tBSI & PPE\t5\tAppropriate PPE selection\nPhase 1\tResource Assessment\t5\tCorrect communication with command\nPhase 2\tTriage Accuracy\t15\tCorrect START triage classification\nPhase 2\tTreatment Prioritization\t10\tAppropriate intervention identification\nPhase 3\tResource Management\t15\tEffective transport priority plan\nPhase 3\tSpecial Considerations\t10\tAppropriate management of special populations\nPhase 4\tReflection\t10\tInsightful reflection on EMS role\nTOTAL\t\t80\t\nPassing Score: 60/80 (75%)", "sourceHeading": "CASE STUDY 1: THE DUSIT D2 HOTEL TERROR ATTACK", "locationLine": "Nairobi, January 15, 2019", "incidentStatistics": ["21 fatalities (including civilians and security personnel)", "28 injured survivors requiring medical evacuation", "Approximately 700 people successfully evacuated", "Duration of operation: Nearly 20 hours", "Response time: First responders arrived within 10 minutes of the initial explosion"], "phases": [{"phase": "PHASE 1", "body": "1. Scene Size-Up & Safety (Critical First Step):\n\nBased on the dispatch information and your knowledge of active shooter/terror incidents, what are your PRIMARY scene safety concerns?\n\nWhat is the difference between the HOT, WARM, and COLD zones at this type of incident?\n\nWhere should you position your ambulance?\n\nYour Response: (fill in)\n\ntext\nHOT ZONE: ________________________________________________________________\nWARM ZONE: _______________________________________________________________\nCOLD ZONE: ________________________________________________________________\nAmbulance positioning: ____________________________________________________\nPrimary safety concerns: __________________________________________________\n2. BSI & PPE Considerations:\n\nWhat personal protective equipment is essential for this scene?\n\nWhat additional precautions might be needed?\n\nYour Response: (fill in)\n\ntext\nEssential PPE: ___________________________________________________________\nAdditional precautions: ___________________________________________________\n3. Triage & Resource Assessment:\n\nWhat is the estimated number of patients based on dispatch?\n\nWhat additional resources would you request?\n\nHow would you establish communication with command?\n\nYour Response: (fill in)\n\ntext\nEstimated patient count: __________________________________________________\nAdditional resources needed: _____________________________________________\nCommunication plan: ______________________________________________________\nPart 2: Arrival at Scene\nYou arrive at the designated casualty collection point approximately 12 minutes after the first dispatch. Security forces have established a secure perimeter. First patients are being evacuated from the building by police and security personnel. \n\nYour initial scene assessment reveals:\n\nSituation: Active shooter incident with hostages reportedly still inside\n\nSecurity: GSU and ATPU are clearing the building floor by floor\n\nPatients: Approximately 15-20 casualties are being brought to the collection point\n\nTriage set-up: The Kenya Red Cross has established a basic triage area\n\nCommunication: Command post established at the corner of Riverside Drive\n\nYou observe the following patients arriving:\n\nPatient\tAge/Sex\tPresentation\tStatus\nA\t35/M\tGunshot wound to the chest, GCS 14, RR 28, BP 100/70\tConscious, in distress\nB\t42/F\tShrapnel wounds to both legs, profuse bleeding, GCS 15\tConscious, anxious\nC\t60/M\tGunshot wound to the abdomen, GCS 10, RR 32, BP 85/55\tSemi-conscious\nD\t28/M\tPanic attack, no visible injuries, GCS 15\tConscious, hyperventilating\nE\t45/F\tGunshot wound to the head, GCS 3, not breathing\tUnconscious, apneic\n\ud83d\uded1"}, {"phase": "PHASE 2", "body": "4. Initial Triage Decision:\nUsing the START (Simple Triage and Rapid Treatment) system, classify each patient:\n\nYour Response: (fill in)\n\ntext\nPatient A (35/M, chest wound, GCS 14, RR 28, BP 100/70):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient B (42/F, shrapnel wounds, GCS 15):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient C (60/M, abdominal wound, GCS 10, RR 32, BP 85/55):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient D (28/M, panic attack, GCS 15):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n\nPatient E (45/F, head wound, GCS 3, apneic):\nColor: _______________\nPriority: _______________\nRationale: ________________________________________________________________\n5. Treatment Prioritization:\n\nWhich patient requires immediate intervention?\n\nWhat specific interventions would you perform for each priority patient?\n\nHow would you coordinate with the Kenya Red Cross team?\n\nYour Response: (fill in)\n\ntext\nImmediate intervention patient: __________________________________________\nInterventions: ___________________________________________________________\nCoordination with Red Cross: _____________________________________________\nPart 3: Mass Casualty Management\nThe situation escalates. More patients are being evacuated from the building. Approximately 30 additional casualties are being transported to the collection point. Security forces are reporting that the attack is still ongoing. Your ambulance can transport 2 patients at a time. Additional ambulances are 15-20 minutes away. \n\nNew arrivals include:\n\n5 patients with blast injuries from the initial explosion\n\n3 patients with gunshot wounds to the extremities\n\n8 patients with smoke inhalation\n\n2 pediatric patients (ages 6 and 8) with shrapnel injuries\n\n12 patients with anxiety/panic attacks\n\n1 pregnant woman with signs of labor (initiated by the stress)\n\nThe Kenya Red Cross triage officer requests your assistance in coordinating the evacuation plan.\n\n\ud83d\uded1"}, {"phase": "PHASE 3", "body": "6. Resource Management & Transport Prioritization:\nDevelop a transport priority plan considering:\n\nAvailable ambulances (your one ALS unit + 2 BLS units on scene)\n\nHospital destination selection (KNH, Aga Khan, Nairobi Hospital)\n\nThe \"Golden Hour\" concept for trauma patients\n\nYour Response: (fill in)\n\ntext\nTransport Priority 1 (Immediate):\nPatient(s): ____________________________________________________________\nDestination: ___________________________________________________________\nRationale: _____________________________________________________________\n\nTransport Priority 2 (Urgent):\nPatient(s): ____________________________________________________________\nDestination: ___________________________________________________________\nRationale: _____________________________________________________________\n\nTransport Priority 3 (Delayed):\nPatient(s): ____________________________________________________________\nDestination: ___________________________________________________________\nRationale: _____________________________________________________________\n7. Special Considerations:\n\nHow do you manage the pediatric patients in a mass casualty setting?\n\nWhat considerations apply to the pregnant patient?\n\nHow would you document this mass casualty incident?\n\nWhat would you tell the receiving hospitals?\n\nYour Response: (fill in)\n\ntext\nPediatric considerations: _______________________________________________\nPregnant patient considerations: ________________________________________\nDocumentation: __________________________________________________________\nHospital notification: __________________________________________________\nPart 4: Lessons Learned - The Dusit Response\nThe response to the Dusit D2 attack was widely praised for its coordination and efficiency compared to the 2013 Westgate Mall attack. \n\nWhat made the Dusit response different?\n\nUnified Command Structure - All units reported to the GSU, eliminating the power struggles seen at Westgate\n\nImproved Intelligence Sharing - The National Counter Terrorism Centre (NCTC) had been strengthened\n\nBetter Equipment and Training - Elite units had received enhanced training with foreign partners\n\nFaster Perimeter Establishment - The area was cordoned off within minutes\n\nRegistration of Evacuees - Survivors were registered to track them and prevent attackers from escaping\n\nMulti-Agency Coordination - KDF, NPS, ATPU, and GSU worked together effectively\n\nSurvival Statistics:\n\nWestgate (2013): 67 deaths, 4 days operation\n\nDusitD2 (2019): 21 deaths, 20 hours operation\n\n\ud83d\uded1"}, {"phase": "PHASE 4", "body": "8. Reflection & Key Takeaways:\n\nYour Response: (fill in)\n\ntext\n1. What role does EMS play in a mass casualty terror incident?\n______________________________________________________________________\n\n2. How did improved incident command affect patient outcomes?\n______________________________________________________________________\n\n3. What are the challenges of providing care in a hostile environment?\n______________________________________________________________________\n\n4. How does START triage help manage mass casualty incidents?\n______________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Phase 1", "component": "Scene Safety Assessment", "points": 10, "criteria": "Correct identification of hot/warm/cold zones"}, {"phase": "Phase 1", "component": "BSI & PPE", "points": 5, "criteria": "Appropriate PPE selection"}, {"phase": "Phase 1", "component": "Resource Assessment", "points": 5, "criteria": "Correct communication with command"}, {"phase": "Phase 2", "component": "Triage Accuracy", "points": 15, "criteria": "Correct START triage classification"}, {"phase": "Phase 2", "component": "Treatment Prioritization", "points": 10, "criteria": "Appropriate intervention identification"}, {"phase": "Phase 3", "component": "Resource Management", "points": 15, "criteria": "Effective transport priority plan"}, {"phase": "Phase 3", "component": "Special Considerations", "points": 10, "criteria": "Appropriate management of special populations"}, {"phase": "Phase 4", "component": "Reflection", "points": 10, "criteria": "Insightful reflection on EMS role"}], "competencies": ["Scene Safety", "Mass Casualty Management", "Trauma", "Communication", "EMS Operations"]}'::jsonb, 1, 75, true)
