INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('49b1f3b9-fdac-5c4a-a75c-38aeddf2e0a6', 'KAKAMEGA PRIMARY SCHOOL STAMPEDE', 'Kakamega, Western Kenya', 'February 3, 2020', 'Pediatric Mass Casualty', 'advanced', 'On February 3, 2020, at approximately 5:00 PM, a tragic stampede occurred at Kakamega Primary School in Western Kenya, resulting in the deaths of 13 children.', '{"rawText": "CASE STUDY 3: KAKAMEGA PRIMARY SCHOOL STAMPEDE\nKakamega, Western Kenya - February 3, 2020\nIncident Background\nOn February 3, 2020, at approximately 5:00 PM, a tragic stampede occurred at Kakamega Primary School in Western Kenya, resulting in the deaths of 13 children. \n\nIncident Statistics:\n\n13 children killed\n\n39 students admitted to hospital\n\n37 students treated and discharged\n\n2 students in intensive care\n\nAge of victims: Mostly grade five, aged 10-12\n\nTime of incident: Around 5:00 PM (1400 GMT)\n\nThe Tragedy: \n\nThe stampede occurred as children were leaving their primary school. The police have launched an inquiry into what caused the crowd of students to panic, leading to the crush. Images broadcast by local media showed parents gathered in front of the emergency ward of a hospital in the town, waiting for news of their children. \n\nWitness Accounts:\n\nOne of the children''s mothers blamed the teachers: \"Those who survived said they were running because there were teachers who were beating them, and that is why they were escaping and fell on each other.\" \n\nCorporal punishment is banned in Kenya.\n\nGovernment Response:\n\nKenya''s Vice President William Ruto stated: \"We are devastated by the tragedy that has hit Kakamega Primary School this evening. Our prayers, love and thoughts to the families and relatives of the victims of the misfortune.\" \n\nKenya Red Cross set up psychological support services and a \"tracing desk\" to help relatives locate potentially affected students. \n\nKakamega police chief David Kabena: \"We have launched an investigation to establish what exactly happened.\" \n\nParliamentary Follow-up:\n\nSenator Bonny Khalwale raised questions in the Senate asking for:\n\nA list of the learners who lost their lives\n\nWhen families will receive compensation awarded by courts\n\nThe amount due to each family\n\nWhen families of three students and a teacher who died from water poisoning at Mukumu Girls'' High School will receive compensation \n\nPart 1: Dispatch Information\nYou are an EMT-Basic with the Kakamega County Ambulance Service. Dispatch receives the following call:\n\nCALLER: \"There has been a stampede at Kakamega Primary School! Children are injured! Many are lying on the ground! Please send help immediately!\"\n\nDISPATCH RECORDS: The call is received at approximately 5:15 PM. Multiple calls are coming in from the school and surrounding area. The county fire brigade and disaster response teams are being mobilized.\n\nYou receive the following dispatch:\n\n\"MASS CASUALTY INCIDENT - SCHOOL STAMPEDE - KAKAMEGA PRIMARY SCHOOL.\n\nConfirmed: Multiple pediatric casualties. Unknown number of injured. Students reportedly trampled.\n\nMulti-agency response: County Disaster Response Teams, Kenya Red Cross, National Police Service, St John Ambulance.\n\nRespond immediately. Be prepared for mass casualty triage of pediatric patients.\"\n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 1\n1. Dispatch & Pre-Arrival Assessment:\n\nYour Response: (fill in)\n\ntext\nWhat is the estimated time to the scene? __________________________________\n\nWhat resources are you bringing? _________________________________________\n\nWhat additional resources should be requested? ____________________________\n\nWhat are your primary concerns for a pediatric mass casualty incident? ______\n__________________________________________________________________________\n2. Pediatric Mass Casualty Considerations:\n\nYour Response: (fill in)\n\ntext\nWhat are the key differences in managing pediatric patients in a mass casualty?\n__________________________________________________________________________\n\nWhat equipment considerations are important? ______________________________\n\nWhat triage considerations apply to pediatric patients? ____________________\n__________________________________________________________________________\nPart 2: Arrival at Scene\nYou arrive at approximately 5:45 PM. The scene is chaotic and emotionally charged: \n\nLocation: Kakamega Primary School, a large public school in Kakamega town\n\nScene: Children are lying on the ground in the school compound. Some are crying, others are silent. There is blood visible on the ground.\n\nBystanders: Parents have arrived in large numbers. Many are crying and searching for their children. The police are struggling to control the crowd.\n\nFirst Responders: St John Ambulance and Kenya Red Cross are on scene but appear overwhelmed by the number of pediatric casualties.\n\nSecurity: Police have cordoned off the area, but parents are breaking through the perimeter.\n\nPatients observed:\n\nPatient\tAge/Sex\tInjuries\tStatus\nA\t10/F\tUnresponsive, no pulse, visible head trauma\tApneic, pulseless\nB\t11/M\tDifficulty breathing, cyanotic, chest pain, RR 40\tConscious, in severe distress\nC\t12/F\tOpen fracture of leg, visible deformity, RR 28\tConscious, crying, in pain\nD\t10/M\tMultiple abrasions, minor lacerations, RR 24\tConscious, crying\nE\t11/F\tHead injury, GCS 10, vomiting, RR 30\tSemi-conscious\nF\t12/M\tAbdominal pain, difficulty breathing, RR 35\tConscious, anxious\nG\t10/F\tAnkle injury, cannot walk, RR 22\tConscious, crying\nH\t11/M\tUnresponsive, pulse present, RR 28, GCS 8\tUnresponsive\nI\t12/F\tMinor abrasions, walking, RR 20\tConscious, crying\nJ\t10/M\tCrush injury to chest, RR 38, HR 140\tConscious, in severe distress\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 2\n3. Pediatric Triage Decision:\nUsing the START triage system adapted for pediatric patients, classify each patient:\n\nYour Response: (fill in)\n\ntext\nPatient A (10/F, unresponsive, apneic, pulseless, head trauma):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient B (11/M, difficulty breathing, cyanotic, RR 40):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient C (12/F, open leg fracture, RR 28):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient D (10/M, minor abrasions, RR 24):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient E (11/F, head injury, GCS 10, vomiting, RR 30):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient F (12/M, abdominal pain, RR 35):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient G (10/F, ankle injury, RR 22):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient H (11/M, unresponsive, GCS 8, RR 28):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient I (12/F, minor abrasions, RR 20):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient J (10/M, crush injury chest, RR 38, HR 140):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n4. Critical Decision: Managing Parents & Bystanders:\n\nHow do you manage the parents who are breaking through the perimeter?\n\nWhat is your communication strategy with families?\n\nHow do you handle the emotional trauma of this incident?\n\nYour Response: (fill in)\n\ntext\nParent management: ________________________________________________________\n__________________________________________________________________________\n\nCommunication with families: ______________________________________________\n__________________________________________________________________________\n\nEmotional trauma support: _________________________________________________\n__________________________________________________________________________\nPart 3: Resource Management & Transport\nThe situation requires significant coordination. \n\nAvailable Resources:\n\nYour ambulance (BLS unit)\n\n2 other county ambulances\n\nSt John Ambulance vehicles\n\nKenya Red Cross first aid teams\n\n2 private ambulances\n\nHospitals Available:\n\nKakamega County Referral Hospital - 10 minutes away - Pediatric ward available\n\nMasinde Muliro Hospital - 20 minutes away - Limited pediatric capacity\n\nJaramogi Oginga Odinga Teaching and Referral Hospital (Kisumu) - 1 hour away - Full pediatric services\n\nPatient Count Update:\n\n13 confirmed fatalities\n\n39 hospital admissions\n\n37 treated and discharged \n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 3\n5. Transport Planning & Resource Allocation:\n\nYour Response: (fill in)\n\ntext\nPriority 1 Patients (Immediate):\nPatient IDs: ____________________________________________________________\nInterventions needed en route: __________________________________________\nDestination hospital: ___________________________________________________\n\nPriority 2 Patients (Urgent):\nPatient IDs: ____________________________________________________________\nInterventions needed en route: __________________________________________\nDestination hospital: ___________________________________________________\n\nPriority 3 Patients (Delayed):\nPatient IDs: ____________________________________________________________\nDestination hospital: ___________________________________________________\n\nFatality Management:\n- Number of deceased: ___________________________________________________\n- Protocol for handling: ________________________________________________\n- Documentation required: _______________________________________________\n6. Psychosocial Support:\n\nHow do you provide psychological support to the survivors?\n\nWhat support is needed for the families?\n\nWhat support is needed for the first responders?\n\nYour Response: (fill in)\n\ntext\nSurvivor support: ________________________________________________________\n__________________________________________________________________________\n\nFamily support: __________________________________________________________\n__________________________________________________________________________\n\nFirst responder support: _________________________________________________\n__________________________________________________________________________\nPart 4: Lessons Learned\nKey Issues Identified: \n\nCorporal punishment: \"Those who survived said they were running because there were teachers who were beating them, and that is why they were escaping and fell on each other.\" Despite corporal punishment being banned in Kenya, it continues to occur.\n\nSchool safety protocols: The incident highlighted the need for improved safety procedures in schools.\n\nEmergency response: While response was swift, the scale of pediatric casualties overwhelmed available resources.\n\nGovernment compensation: Four years later, families were still awaiting compensation awarded by the courts. \n\nPsychosocial support: Kenya Red Cross established psychological support services and a \"tracing desk\" to help relatives locate potentially affected students. \n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 4\n7. Reflection & Prevention:\n\nYour Response: (fill in)\n\ntext\n1. What are the systemic issues that contributed to this tragedy?\n\n______________________________________________________________________\n______________________________________________________________________\n\n2. What could have prevented this stampede?\n\n______________________________________________________________________\n______________________________________________________________________\n\n3. How can EMS prepare for pediatric mass casualty incidents?\n\n______________________________________________________________________\n______________________________________________________________________\n\n4. What role does psychosocial support play in school emergencies?\n\n______________________________________________________________________\n______________________________________________________________________\n\n5. As an EMT, what would you recommend to prevent future school tragedies?\n\n______________________________________________________________________\n______________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nPhase 1\tDispatch Assessment\t10\tCorrect identification of response needs\nPhase 1\tPediatric Considerations\t10\tUnderstanding of pediatric MCI challenges\nPhase 2\tTriage Accuracy\t15\tCorrect START triage for pediatric patients\nPhase 2\tParent Management\t10\tAppropriate handling of family/crowd control\nPhase 3\tTransport Planning\t15\tEffective resource allocation to appropriate destinations\nPhase 3\tPsychosocial Support\t10\tUnderstanding of psychological support needs\nPhase 4\tLessons Learned\t10\tInsightful analysis of contributing factors\nTOTAL\t\t80\t\nPassing Score: 60/80 (75%)", "sourceHeading": "CASE STUDY 3: KAKAMEGA PRIMARY SCHOOL STAMPEDE", "locationLine": "Kakamega, Western Kenya - February 3, 2020", "incidentStatistics": ["13 children killed", "39 students admitted to hospital", "37 students treated and discharged", "2 students in intensive care", "Age of victims: Mostly grade five, aged 10-12", "Time of incident: Around 5:00 PM (1400 GMT)"], "phases": [{"phase": "PHASE 1", "body": "1. Dispatch & Pre-Arrival Assessment:\n\nYour Response: (fill in)\n\ntext\nWhat is the estimated time to the scene? __________________________________\n\nWhat resources are you bringing? _________________________________________\n\nWhat additional resources should be requested? ____________________________\n\nWhat are your primary concerns for a pediatric mass casualty incident? ______\n__________________________________________________________________________\n2. Pediatric Mass Casualty Considerations:\n\nYour Response: (fill in)\n\ntext\nWhat are the key differences in managing pediatric patients in a mass casualty?\n__________________________________________________________________________\n\nWhat equipment considerations are important? ______________________________\n\nWhat triage considerations apply to pediatric patients? ____________________\n__________________________________________________________________________\nPart 2: Arrival at Scene\nYou arrive at approximately 5:45 PM. The scene is chaotic and emotionally charged: \n\nLocation: Kakamega Primary School, a large public school in Kakamega town\n\nScene: Children are lying on the ground in the school compound. Some are crying, others are silent. There is blood visible on the ground.\n\nBystanders: Parents have arrived in large numbers. Many are crying and searching for their children. The police are struggling to control the crowd.\n\nFirst Responders: St John Ambulance and Kenya Red Cross are on scene but appear overwhelmed by the number of pediatric casualties.\n\nSecurity: Police have cordoned off the area, but parents are breaking through the perimeter.\n\nPatients observed:\n\nPatient\tAge/Sex\tInjuries\tStatus\nA\t10/F\tUnresponsive, no pulse, visible head trauma\tApneic, pulseless\nB\t11/M\tDifficulty breathing, cyanotic, chest pain, RR 40\tConscious, in severe distress\nC\t12/F\tOpen fracture of leg, visible deformity, RR 28\tConscious, crying, in pain\nD\t10/M\tMultiple abrasions, minor lacerations, RR 24\tConscious, crying\nE\t11/F\tHead injury, GCS 10, vomiting, RR 30\tSemi-conscious\nF\t12/M\tAbdominal pain, difficulty breathing, RR 35\tConscious, anxious\nG\t10/F\tAnkle injury, cannot walk, RR 22\tConscious, crying\nH\t11/M\tUnresponsive, pulse present, RR 28, GCS 8\tUnresponsive\nI\t12/F\tMinor abrasions, walking, RR 20\tConscious, crying\nJ\t10/M\tCrush injury to chest, RR 38, HR 140\tConscious, in severe distress\n\ud83d\uded1"}, {"phase": "PHASE 2", "body": "3. Pediatric Triage Decision:\nUsing the START triage system adapted for pediatric patients, classify each patient:\n\nYour Response: (fill in)\n\ntext\nPatient A (10/F, unresponsive, apneic, pulseless, head trauma):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient B (11/M, difficulty breathing, cyanotic, RR 40):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient C (12/F, open leg fracture, RR 28):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient D (10/M, minor abrasions, RR 24):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient E (11/F, head injury, GCS 10, vomiting, RR 30):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient F (12/M, abdominal pain, RR 35):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient G (10/F, ankle injury, RR 22):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient H (11/M, unresponsive, GCS 8, RR 28):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient I (12/F, minor abrasions, RR 20):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n\nPatient J (10/M, crush injury chest, RR 38, HR 140):\nColor: _______________ Priority: _______________\nRationale: ________________________________________________________________\n4. Critical Decision: Managing Parents & Bystanders:\n\nHow do you manage the parents who are breaking through the perimeter?\n\nWhat is your communication strategy with families?\n\nHow do you handle the emotional trauma of this incident?\n\nYour Response: (fill in)\n\ntext\nParent management: ________________________________________________________\n__________________________________________________________________________\n\nCommunication with families: ______________________________________________\n__________________________________________________________________________\n\nEmotional trauma support: _________________________________________________\n__________________________________________________________________________\nPart 3: Resource Management & Transport\nThe situation requires significant coordination. \n\nAvailable Resources:\n\nYour ambulance (BLS unit)\n\n2 other county ambulances\n\nSt John Ambulance vehicles\n\nKenya Red Cross first aid teams\n\n2 private ambulances\n\nHospitals Available:\n\nKakamega County Referral Hospital - 10 minutes away - Pediatric ward available\n\nMasinde Muliro Hospital - 20 minutes away - Limited pediatric capacity\n\nJaramogi Oginga Odinga Teaching and Referral Hospital (Kisumu) - 1 hour away - Full pediatric services\n\nPatient Count Update:\n\n13 confirmed fatalities\n\n39 hospital admissions\n\n37 treated and discharged \n\n\ud83d\uded1"}, {"phase": "PHASE 3", "body": "5. Transport Planning & Resource Allocation:\n\nYour Response: (fill in)\n\ntext\nPriority 1 Patients (Immediate):\nPatient IDs: ____________________________________________________________\nInterventions needed en route: __________________________________________\nDestination hospital: ___________________________________________________\n\nPriority 2 Patients (Urgent):\nPatient IDs: ____________________________________________________________\nInterventions needed en route: __________________________________________\nDestination hospital: ___________________________________________________\n\nPriority 3 Patients (Delayed):\nPatient IDs: ____________________________________________________________\nDestination hospital: ___________________________________________________\n\nFatality Management:\n- Number of deceased: ___________________________________________________\n- Protocol for handling: ________________________________________________\n- Documentation required: _______________________________________________\n6. Psychosocial Support:\n\nHow do you provide psychological support to the survivors?\n\nWhat support is needed for the families?\n\nWhat support is needed for the first responders?\n\nYour Response: (fill in)\n\ntext\nSurvivor support: ________________________________________________________\n__________________________________________________________________________\n\nFamily support: __________________________________________________________\n__________________________________________________________________________\n\nFirst responder support: _________________________________________________\n__________________________________________________________________________\nPart 4: Lessons Learned\nKey Issues Identified: \n\nCorporal punishment: \"Those who survived said they were running because there were teachers who were beating them, and that is why they were escaping and fell on each other.\" Despite corporal punishment being banned in Kenya, it continues to occur.\n\nSchool safety protocols: The incident highlighted the need for improved safety procedures in schools.\n\nEmergency response: While response was swift, the scale of pediatric casualties overwhelmed available resources.\n\nGovernment compensation: Four years later, families were still awaiting compensation awarded by the courts. \n\nPsychosocial support: Kenya Red Cross established psychological support services and a \"tracing desk\" to help relatives locate potentially affected students. \n\n\ud83d\uded1"}, {"phase": "PHASE 4", "body": "7. Reflection & Prevention:\n\nYour Response: (fill in)\n\ntext\n1. What are the systemic issues that contributed to this tragedy?\n\n______________________________________________________________________\n______________________________________________________________________\n\n2. What could have prevented this stampede?\n\n______________________________________________________________________\n______________________________________________________________________\n\n3. How can EMS prepare for pediatric mass casualty incidents?\n\n______________________________________________________________________\n______________________________________________________________________\n\n4. What role does psychosocial support play in school emergencies?\n\n______________________________________________________________________\n______________________________________________________________________\n\n5. As an EMT, what would you recommend to prevent future school tragedies?\n\n______________________________________________________________________\n______________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Phase 1", "component": "Dispatch Assessment", "points": 10, "criteria": "Correct identification of response needs"}, {"phase": "Phase 1", "component": "Pediatric Considerations", "points": 10, "criteria": "Understanding of pediatric MCI challenges"}, {"phase": "Phase 2", "component": "Triage Accuracy", "points": 15, "criteria": "Correct START triage for pediatric patients"}, {"phase": "Phase 2", "component": "Parent Management", "points": 10, "criteria": "Appropriate handling of family/crowd control"}, {"phase": "Phase 3", "component": "Transport Planning", "points": 15, "criteria": "Effective resource allocation to appropriate destinations"}, {"phase": "Phase 3", "component": "Psychosocial Support", "points": 10, "criteria": "Understanding of psychological support needs"}, {"phase": "Phase 4", "component": "Lessons Learned", "points": 10, "criteria": "Insightful analysis of contributing factors"}], "competencies": ["Scene Safety", "Mass Casualty Management", "Trauma", "Pediatric Emergencies", "Communication", "EMS Operations"]}'::jsonb, 3, 75, true)
