INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('2645f2a2-a8f1-5356-8cc8-36d9c9c6ae38', 'NAIROBI BUS MASS CASUALTY INCIDENT', 'Kenyatta Avenue, Nairobi', 'October 14, 2025', 'Road Traffic Mass Casualty', 'intermediate', 'At approximately 12:30 AM on October 14, 2025, a Citi Hoppa bus was involved in a serious accident along Kenyatta Avenue near Serena Hotel in Nairobi.', '{"rawText": "CASE STUDY 4: NAIROBI BUS MASS CASUALTY INCIDENT\nKenyatta Avenue, Nairobi - October 14, 2025\nIncident Background\nAt approximately 12:30 AM on October 14, 2025, a Citi Hoppa bus was involved in a serious accident along Kenyatta Avenue near Serena Hotel in Nairobi. \n\nIncident Statistics:\n\n24 casualties admitted to Kenyatta National Hospital\n\n11 females, 13 males among the casualties\n\nMultiple patients were trapped under the bus\n\nResources overwhelmed: \"I have mobilised all available county ambulances, but they are not enough. If you have an ambulance, please come and assist us immediately\"\n\nContext of Road Safety Crisis:\n\nJust days earlier, another accident occurred at Waruku\n\nNairobi County has only 20 ambulances - far short of the 50 required\n\nResponse times range from 20 to 60 minutes depending on traffic\n\nPart 1: Dispatch Information\nYou receive the following dispatch:\n\n\"MASS CASUALTY INCIDENT - ROAD TRAFFIC CRASH - KENYATTA AVENUE NEAR SERENA HOTEL.\n\nConfirmed: Bus accident with multiple trapped and injured.\n\nResponse: All available ambulances in Nairobi are being mobilised.\n\nProceed immediately. Coordinate with Kenya Red Cross at the scene.\"\n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 1\n1. Pre-Arrival Assessment:\n\nYour Response: (fill in)\n\ntext\nLocation and route considerations: ________________________________________\nWhat equipment is most critical for this call? ___________________________\nWhat information do you need from dispatch? ______________________________\n2. Anticipating Mass Casualty Needs:\n\nYour Response: (fill in)\n\ntext\nResource needs: __________________________________________________________\nExpected injury patterns: ________________________________________________\nPart 2: Arrival at Scene\nScene Assessment: \n\nYou arrive at 12:45 AM. The scene is chaotic:\n\nVehicle: A Citi Hoppa bus on its side, with significant damage. The front of the bus is crushed. Several passengers are trapped inside.\n\nPatients: Victims are everywhere - some are lying on the road, others are wandering in shock. Some are trapped under the vehicle.\n\nBystanders: A large crowd has gathered. Many are trying to help, but this is complicating access for responders.\n\nPolice: Police are on scene but are struggling to control the crowd.\n\nAmbulances: Four ambulances are on scene (including yours). More are needed.\n\nPatients you identify:\n\nPatient\tAge/Sex\tInjuries\tPriority\nA\t35/M\tTrapped under bus, conscious, leg crushed, BP 85/55, HR 120\t?\nB\t28/F\tMultiple lacerations, head injury, GCS 12, BP 100/70\t?\nC\t42/M\tAmbulatory, minor abrasions, GCS 15\t?\nD\t60/F\tChest pain, difficulty breathing, BP 140/90, HR 100\t?\nE\t22/F\tUnconscious, trapped in bus, head injury, GCS 6, RR 28\t?\nF\t45/M\tSpinal injury suspected, GCS 15, no motor function in legs\t?\nG\t30/F\tPanic attack, hyperventilating, no visible injuries\t?\nH\t50/M\tSevere bleeding from arm laceration, BP 90/60, HR 125\t?\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 2\n3. Triage & Treatment Decisions:\n\nYour Response: (fill in)\n\ntext\nPatient A (35/M, trapped, leg crushed, BP 85/55, HR 120):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient B (28/F, head injury, GCS 12, BP 100/70):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient C (42/M, ambulatory, minor abrasions):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient D (60/F, chest pain, BP 140/90):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient E (22/F, trapped, head injury, GCS 6, RR 28):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient F (45/M, spinal injury, paralysis suspected):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient G (30/F, panic attack):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient H (50/M, severe bleeding, BP 90/60, HR 125):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nPhase 1\tPre-Arrival Assessment\t10\tCorrect identification of scene needs\nPhase 2\tTriage Accuracy\t15\tCorrect START triage classification\nPhase 2\tExtrication Management\t10\tAppropriate management of trapped patients\nPhase 3\tTransport Planning\t15\tEffective allocation to destinations\nPhase 3\tSystem Analysis\t10\tInsightful analysis of systemic barriers\nPhase 4\tReflection\t10\tUnderstanding of EMS system issues\nTOTAL\t\t70\t\nPassing Score: 50/70 (71%)", "sourceHeading": "CASE STUDY 4: NAIROBI BUS MASS CASUALTY INCIDENT", "locationLine": "Kenyatta Avenue, Nairobi - October 14, 2025", "incidentStatistics": ["24 casualties admitted to Kenyatta National Hospital", "11 females, 13 males among the casualties", "Multiple patients were trapped under the bus", "Resources overwhelmed: \"I have mobilised all available county ambulances, but they are not enough. If you have an ambulance, please come and assist us immediately\"", "Context of Road Safety Crisis:", "Just days earlier, another accident occurred at Waruku", "Nairobi County has only 20 ambulances - far short of the 50 required", "Response times range from 20 to 60 minutes depending on traffic"], "phases": [{"phase": "PHASE 1", "body": "1. Pre-Arrival Assessment:\n\nYour Response: (fill in)\n\ntext\nLocation and route considerations: ________________________________________\nWhat equipment is most critical for this call? ___________________________\nWhat information do you need from dispatch? ______________________________\n2. Anticipating Mass Casualty Needs:\n\nYour Response: (fill in)\n\ntext\nResource needs: __________________________________________________________\nExpected injury patterns: ________________________________________________\nPart 2: Arrival at Scene\nScene Assessment: \n\nYou arrive at 12:45 AM. The scene is chaotic:\n\nVehicle: A Citi Hoppa bus on its side, with significant damage. The front of the bus is crushed. Several passengers are trapped inside.\n\nPatients: Victims are everywhere - some are lying on the road, others are wandering in shock. Some are trapped under the vehicle.\n\nBystanders: A large crowd has gathered. Many are trying to help, but this is complicating access for responders.\n\nPolice: Police are on scene but are struggling to control the crowd.\n\nAmbulances: Four ambulances are on scene (including yours). More are needed.\n\nPatients you identify:\n\nPatient\tAge/Sex\tInjuries\tPriority\nA\t35/M\tTrapped under bus, conscious, leg crushed, BP 85/55, HR 120\t?\nB\t28/F\tMultiple lacerations, head injury, GCS 12, BP 100/70\t?\nC\t42/M\tAmbulatory, minor abrasions, GCS 15\t?\nD\t60/F\tChest pain, difficulty breathing, BP 140/90, HR 100\t?\nE\t22/F\tUnconscious, trapped in bus, head injury, GCS 6, RR 28\t?\nF\t45/M\tSpinal injury suspected, GCS 15, no motor function in legs\t?\nG\t30/F\tPanic attack, hyperventilating, no visible injuries\t?\nH\t50/M\tSevere bleeding from arm laceration, BP 90/60, HR 125\t?\n\ud83d\uded1"}, {"phase": "PHASE 2", "body": "3. Triage & Treatment Decisions:\n\nYour Response: (fill in)\n\ntext\nPatient A (35/M, trapped, leg crushed, BP 85/55, HR 120):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient B (28/F, head injury, GCS 12, BP 100/70):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient C (42/M, ambulatory, minor abrasions):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient D (60/F, chest pain, BP 140/90):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient E (22/F, trapped, head injury, GCS 6, RR 28):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient F (45/M, spinal injury, paralysis suspected):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient G (30/F, panic attack):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\nPatient H (50/M, severe bleeding, BP 90/60, HR 125):\nColor: _______________ Priority: _______________\nImmediate interventions: __________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Phase 1", "component": "Pre-Arrival Assessment", "points": 10, "criteria": "Correct identification of scene needs"}, {"phase": "Phase 2", "component": "Triage Accuracy", "points": 15, "criteria": "Correct START triage classification"}, {"phase": "Phase 2", "component": "Extrication Management", "points": 10, "criteria": "Appropriate management of trapped patients"}, {"phase": "Phase 3", "component": "Transport Planning", "points": 15, "criteria": "Effective allocation to destinations"}, {"phase": "Phase 3", "component": "System Analysis", "points": 10, "criteria": "Insightful analysis of systemic barriers"}, {"phase": "Phase 4", "component": "Reflection", "points": 10, "criteria": "Understanding of EMS system issues"}], "competencies": ["Scene Safety", "Mass Casualty Management", "Trauma", "Communication", "EMS Operations"]}'::jsonb, 4, 71, true)
