INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('9438a8d9-a90c-577c-b7cf-6ee943387ebd', 'KISUMU BUILDING COLLAPSE RESCUE', 'Tom Mboya Estate, Kisumu', 'May 11, 2026', 'Structural Collapse Rescue', 'advanced', 'On May 11, 2026, at approximately 8:00 PM, a four-storey building under construction collapsed in the Tom Mboya Estate, Kisumu.', '{"rawText": "CASE STUDY 5: KISUMU BUILDING COLLAPSE RESCUE\nTom Mboya Estate, Kisumu - May 11, 2026\nIncident Background\nOn May 11, 2026, at approximately 8:00 PM, a four-storey building under construction collapsed in the Tom Mboya Estate, Kisumu. \n\nIncident Statistics:\n\n1 victim successfully rescued alive\n\nDistress call: Received at 8:06 PM\n\nResponse time: 20 minutes (within international standards)\n\nRescue time: Victim rescued at 3:00 AM (7 hours after collapse)\n\nMultiple agencies: Emergency Operations Centre, Fire Department, Kenya Red Cross, County Police, Ambulance Services\n\nThe Successful Response:\n\"The victim was successfully rescued at around 3 a.m. after hours of careful excavation and rescue efforts\" \n\nThe Building Collapse Crisis (Kenya)\n2026 Incidents in Nairobi alone: \n\nJanuary 2: Multi-storey building collapsed in South C estate, 2 guards killed\n\nJanuary 10: Building crumbled in Karen, 2 lives lost, several injured\n\nFebruary 10: Building collapsed near OTC, 6 workers rescued\n\nThe South C Incident: \"Early assessments by Cabinet Secretary Geoffrey Ruku suggest the structure may have failed due to column overload. Officials say the building had been approved for 12 storeys but had reportedly reached between 14 and 16 storeys before it collapsed\"\n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 1\n1. Scene Assessment:\n\nYour Response: (fill in)\n\ntext\nPrimary safety concerns: __________________________________________________\nEquipment needed: ________________________________________________________\nResource requirements: ____________________________________________________\nStaging plan: ____________________________________________________________\n2. Triage Categories for Rescue Operations:\n\nYour Response: (fill in)\n\ntext\nUnique challenges: ________________________________________________________\nRescue triage differences: ________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nPhase 1\tScene Assessment\t10\tCorrect identification of hazards\nPhase 1\tRescue Triaging\t10\tUnderstanding of rescue challenges\nPhase 2\tRescue Operations\t15\tAppropriate EMS role identification\nPhase 2\tVictim Management\t15\tCorrect management of crush injury\nPhase 3\tPatient Care Documentation\t15\tComplete and accurate documentation\nPhase 3\tLessons Learned\t15\tInsightful analysis of success factors\nTOTAL\t\t80\t\nPassing Score: 60/80 (75%)", "sourceHeading": "CASE STUDY 5: KISUMU BUILDING COLLAPSE RESCUE", "locationLine": "Tom Mboya Estate, Kisumu - May 11, 2026", "incidentStatistics": [], "phases": [{"phase": "PHASE 1", "body": "1. Scene Assessment:\n\nYour Response: (fill in)\n\ntext\nPrimary safety concerns: __________________________________________________\nEquipment needed: ________________________________________________________\nResource requirements: ____________________________________________________\nStaging plan: ____________________________________________________________\n2. Triage Categories for Rescue Operations:\n\nYour Response: (fill in)\n\ntext\nUnique challenges: ________________________________________________________\nRescue triage differences: ________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Phase 1", "component": "Scene Assessment", "points": 10, "criteria": "Correct identification of hazards"}, {"phase": "Phase 1", "component": "Rescue Triaging", "points": 10, "criteria": "Understanding of rescue challenges"}, {"phase": "Phase 2", "component": "Rescue Operations", "points": 15, "criteria": "Appropriate EMS role identification"}, {"phase": "Phase 2", "component": "Victim Management", "points": 15, "criteria": "Correct management of crush injury"}, {"phase": "Phase 3", "component": "Patient Care Documentation", "points": 15, "criteria": "Complete and accurate documentation"}, {"phase": "Phase 3", "component": "Lessons Learned", "points": 15, "criteria": "Insightful analysis of success factors"}], "competencies": ["Scene Safety", "Trauma", "Communication", "EMS Operations"]}'::jsonb, 5, 75, true)
