INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('4669e4df-9f01-59c9-be2e-90dcfff245ce', 'KAKAMEGA FUNERAL BUS CRASH', 'Kisumu-Kakamega Highway', 'August 8, 2025', 'Road Traffic Mass Casualty', 'intermediate', 'On August 8, 2025, a bus carrying mourners returning from a funeral crashed along the Kisumu-Kakamega Highway.', '{"rawText": "CASE STUDY 6: KAKAMEGA FUNERAL BUS CRASH\nKisumu-Kakamega Highway - August 8, 2025\nIncident Background\nOn August 8, 2025, a bus carrying mourners returning from a funeral crashed along the Kisumu-Kakamega Highway. \n\nIncident Statistics:\n\n25 total deaths (21 at scene, 4 in hospital)\n\n10 women, 10 men, 1 girl died at the scene\n\n20 passengers injured (5 seriously)\n\nAll passengers from one family\n\nLocation: Near a roundabout on the Kisumu-Kakamega Highway\n\nVehicle: Secondary school bus being used for funeral transport\n\nThe Crash: \n\n\"The driver lost control, veered off the road and overturned into a ditch along the Kisumu-Kakamega Highway on Friday afternoon,\" a police report seen by the BBC says. The area is notorious for many deadly accidents.\n\nAccording to Peter Maina, a regional traffic enforcement officer for Nyanza province, the driver lost control of the bus as it approached a roundabout at high speed and plunged into a ditch. \n\nGovernment Response:\n\nKenya''s Ministry of Health called for an \"urgent blood drive\" to help survivors\n\nKenyan President William Ruto called for authorities to quickly book \"those responsible for any acts of negligence leading to the accident\" \n\nNational Transport and Safety Authority (NTSA) will aid investigations\n\nContext of Road Safety Crisis:\n\nRoad deaths in Kenya rose more than 20% between 2020-2021\n\nIn 2021, more than 4,500 people were killed and more than 16,000 injured\n\nThis area is notorious for many deadly accidents \n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 1\n1. Dispatch & Pre-Arrival Assessment:\n\nYour Response: (fill in)\n\ntext\nLocation: Kisumu-Kakamega Highway\nEstimated time to scene: _________________________________________________\n\nWhat are the likely injuries from a rollover bus crash? ___________________\n\nWhat resources would you request? ________________________________________\n2. Mass Casualty Considerations:\n\nYour Response: (fill in)\n\ntext\nWhat makes this a mass casualty incident? _________________________________\n\nWhat are the key differences between a bus crash and other MCIs? ___________\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 2\n3. Triage & Initial Assessment:\n\nYour Response: (fill in)\n\ntext\nHow do you prioritize patients when all are from one family? ______________\n__________________________________________________________________________\n\nWhat psychological considerations apply to this incident? _________________\n__________________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nPhase 1\tDispatch Assessment\t10\tCorrect identification of response needs\nPhase 1\tMass Casualty Considerations\t10\tUnderstanding of MCI challenges\nPhase 2\tTriage Decision\t15\tCorrect START triage classification\nPhase 2\tCommunication\t10\tAppropriate communication with families\nPhase 3\tHospital Coordination\t10\tEffective coordination with receiving facilities\nPhase 4\tReflection\t15\tUnderstanding of road safety issues\nTOTAL\t\t70\t\nPassing Score: 50/70 (71%)", "sourceHeading": "CASE STUDY 6: KAKAMEGA FUNERAL BUS CRASH", "locationLine": "Kisumu-Kakamega Highway - August 8, 2025", "incidentStatistics": ["25 total deaths (21 at scene, 4 in hospital)", "10 women, 10 men, 1 girl died at the scene", "20 passengers injured (5 seriously)", "All passengers from one family", "Location: Near a roundabout on the Kisumu-Kakamega Highway", "Vehicle: Secondary school bus being used for funeral transport"], "phases": [{"phase": "PHASE 1", "body": "1. Dispatch & Pre-Arrival Assessment:\n\nYour Response: (fill in)\n\ntext\nLocation: Kisumu-Kakamega Highway\nEstimated time to scene: _________________________________________________\n\nWhat are the likely injuries from a rollover bus crash? ___________________\n\nWhat resources would you request? ________________________________________\n2. Mass Casualty Considerations:\n\nYour Response: (fill in)\n\ntext\nWhat makes this a mass casualty incident? _________________________________\n\nWhat are the key differences between a bus crash and other MCIs? ___________\n\ud83d\uded1"}, {"phase": "PHASE 2", "body": "3. Triage & Initial Assessment:\n\nYour Response: (fill in)\n\ntext\nHow do you prioritize patients when all are from one family? ______________\n__________________________________________________________________________\n\nWhat psychological considerations apply to this incident? _________________\n__________________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Phase 1", "component": "Dispatch Assessment", "points": 10, "criteria": "Correct identification of response needs"}, {"phase": "Phase 1", "component": "Mass Casualty Considerations", "points": 10, "criteria": "Understanding of MCI challenges"}, {"phase": "Phase 2", "component": "Triage Decision", "points": 15, "criteria": "Correct START triage classification"}, {"phase": "Phase 2", "component": "Communication", "points": 10, "criteria": "Appropriate communication with families"}, {"phase": "Phase 3", "component": "Hospital Coordination", "points": 10, "criteria": "Effective coordination with receiving facilities"}, {"phase": "Phase 4", "component": "Reflection", "points": 15, "criteria": "Understanding of road safety issues"}], "competencies": ["Scene Safety", "Mass Casualty Management", "Trauma", "Communication", "EMS Operations"]}'::jsonb, 6, 71, true)
