INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('197f93b6-1911-540a-aad6-292237b61e7c', 'KAREN BUILDING COLLAPSE', 'Karen, Nairobi', 'January 10, 2026', 'Structural Collapse Rescue', 'advanced', 'On January 10, 2026, a residential building under construction collapsed along Ngong View Lane in Karen, Nairobi.', '{"rawText": "CASE STUDY 7: KAREN BUILDING COLLAPSE\nKaren, Nairobi - January 10, 2026\nIncident Background\nOn January 10, 2026, a residential building under construction collapsed along Ngong View Lane in Karen, Nairobi. \n\nIncident Statistics:\n\n2 deaths (severe crush injuries)\n\n7 injured rescued and rushed to hospital\n\nLocation: Karen Ward, Lang''ata Sub-County\n\nTime of collapse: During construction work\n\nCause of Collapse: \n\nPreliminary investigations pointed to structural failure linked to poor workmanship and inadequate formwork.\n\n\"Preliminary investigations indicate the collapse was caused by structural failure resulting from poor workmanship and inadequate formwork. Initial findings show the use of sub-standard materials, where timber gum tree supports were used instead of appropriate steel props for the double-volume slab.\" - Nairobi CEC Member Patrick Mbogo \n\nProject Details:\n\nDeveloper: Moses A. Nyakiogora\n\nStructural Engineer: Eng. Edward Kariuki\n\nArchitectural plans approved: November 14, 2024\n\nStructural plans approved: November 27, 2024\n\nThe Indemnity Form: \n\nUnder the indemnity form, developers indemnify the county and the County Structural Engineer against claims arising from collapse, injury or loss of life. By signing it, developers commit to:\n\nEngaging qualified and registered professionals\n\nAdhering to approved drawings and building codes\n\nEnsuring proper site supervision\n\nSubmitting mandatory material test results\n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 1\n1. Scene & Safety Assessment:\n\nYour Response: (fill in)\n\ntext\nWhat are the primary safety concerns at a building collapse scene? _________\n\nWhat equipment is needed for a rescue operation? __________________________\n\nWhat additional resources would you request? _____________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nPhase 1\tScene Assessment\t15\tCorrect identification of hazards\nPhase 1\tResource Assessment\t10\tAppropriate resource request\nPhase 2\tRescue Operations\t15\tUnderstanding of EMS role\nPhase 2\tPatient Management\t10\tCorrect management of crush injuries\nPhase 3\tSystem Analysis\t15\tInsightful analysis of regulatory issues\nTOTAL\t\t65\t\nPassing Score: 45/65 (69%)", "sourceHeading": "CASE STUDY 7: KAREN BUILDING COLLAPSE", "locationLine": "Karen, Nairobi - January 10, 2026", "incidentStatistics": [], "phases": [{"phase": "PHASE 1", "body": "1. Scene & Safety Assessment:\n\nYour Response: (fill in)\n\ntext\nWhat are the primary safety concerns at a building collapse scene? _________\n\nWhat equipment is needed for a rescue operation? __________________________\n\nWhat additional resources would you request? _____________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Phase 1", "component": "Scene Assessment", "points": 15, "criteria": "Correct identification of hazards"}, {"phase": "Phase 1", "component": "Resource Assessment", "points": 10, "criteria": "Appropriate resource request"}, {"phase": "Phase 2", "component": "Rescue Operations", "points": 15, "criteria": "Understanding of EMS role"}, {"phase": "Phase 2", "component": "Patient Management", "points": 10, "criteria": "Correct management of crush injuries"}, {"phase": "Phase 3", "component": "System Analysis", "points": 15, "criteria": "Insightful analysis of regulatory issues"}], "competencies": ["Scene Safety", "Trauma", "Communication", "EMS Operations"]}'::jsonb, 7, 69, true)
