INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('63478215-e1de-5f3c-9ae9-1b96546cff30', 'JOMO KENYATTA INTERNATIONAL AIRPORT (JKIA) EMERGENCY DRILL & INCIDENTS', 'Nairobi', 'Various Dates', 'Aircraft Emergency Preparedness', 'intermediate', 'March 20, 2026 - Wilson Airport Crash Landing: A passenger plane crash-landed at Wilson Airport in Nairobi, triggering an emergency response. The aircraft, registered as 5Y-BXI and operated by Aircraft Leasing Services (ALS), had been flying from Kisumu. ALS was known for operating flights for humanitarian agencies including the UN World Food Programme and the International Committee of the Red Cross.', '{"rawText": "CASE STUDY 8: JOMO KENYATTA INTERNATIONAL AIRPORT (JKIA) EMERGENCY DRILL & INCIDENTS\nNairobi - Various Dates\nIncident Background\nMarch 20, 2026 - Wilson Airport Crash Landing: A passenger plane crash-landed at Wilson Airport in Nairobi, triggering an emergency response. The aircraft, registered as 5Y-BXI and operated by Aircraft Leasing Services (ALS), had been flying from Kisumu. ALS was known for operating flights for humanitarian agencies including the UN World Food Programme and the International Committee of the Red Cross. \n\nApril 24, 2026 - Mandera Runway Excursion: A commercial passenger plane on the Nairobi-Mandera route veered off the runway and ended up in surrounding vegetation at the Mandera Airstrip. All 32 passengers and 4 crew members were safely evacuated with no injuries reported. \n\nJune 11, 2026 - JKIA Emergency Drill: The Kenya Airports Authority (KAA) confirmed an emergency situation at JKIA was actually a simulated scenario conducted as part of a planned Full-Scale Emergency Exercise. Emergency response teams and agencies had been activated in accordance with established emergency procedures. \n\n\ud83d\uded1 STUDENT ACTION REQUIRED - PHASE 1\n1. Aircraft Incident Response Planning:\n\nYour Response: (fill in)\n\ntext\nWhat are the unique challenges of an aircraft incident response? ___________\n\nWhat are the triage considerations for an aircraft incident? ______________\n\nWhat resources are typically required? ____________________________________\n2. Emergency Drill Considerations:\n\nYour Response: (fill in)\n\ntext\nWhy are emergency drills important for airport incidents? _________________\n\nHow do drills help prepare for real incidents? ___________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nPhase 1\tIncident Planning\t15\tUnderstanding of aircraft incident challenges\nPhase 1\tTriage Considerations\t10\tAppropriate MCI planning\nPhase 2\tDrill Importance\t10\tUnderstanding of preparedness\nPhase 3\tLessons Learned\t15\tInsightful analysis of system gaps\nTOTAL\t\t50\t\nPassing Score: 35/50 (70%)", "sourceHeading": "CASE STUDY 8: JOMO KENYATTA INTERNATIONAL AIRPORT (JKIA) EMERGENCY DRILL & INCIDENTS", "locationLine": "Nairobi - Various Dates", "incidentStatistics": [], "phases": [{"phase": "PHASE 1", "body": "1. Aircraft Incident Response Planning:\n\nYour Response: (fill in)\n\ntext\nWhat are the unique challenges of an aircraft incident response? ___________\n\nWhat are the triage considerations for an aircraft incident? ______________\n\nWhat resources are typically required? ____________________________________\n2. Emergency Drill Considerations:\n\nYour Response: (fill in)\n\ntext\nWhy are emergency drills important for airport incidents? _________________\n\nHow do drills help prepare for real incidents? ___________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Phase 1", "component": "Incident Planning", "points": 15, "criteria": "Understanding of aircraft incident challenges"}, {"phase": "Phase 1", "component": "Triage Considerations", "points": 10, "criteria": "Appropriate MCI planning"}, {"phase": "Phase 2", "component": "Drill Importance", "points": 10, "criteria": "Understanding of preparedness"}, {"phase": "Phase 3", "component": "Lessons Learned", "points": 15, "criteria": "Insightful analysis of system gaps"}], "competencies": ["Scene Safety", "Mass Casualty Management", "Communication", "EMS Operations"]}'::jsonb, 8, 70, true)
