INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('b86e013e-e605-5378-b617-6a08e4dae109', 'MICHAEL WAFULA - 5 HOURS, NO AMBULANCE', 'Machakos County', 'April 2026', 'EMS System Failure', 'intermediate', 'Michael Wafula did not die from the impact of the vehicle that struck him. He died from what came after: 30 calls, and not one of them reached anyone who could help.', '{"rawText": "CASE STUDY 9: MICHAEL WAFULA - 5 HOURS, NO AMBULANCE\nMachakos County - April 2026\nIncident Background\nMichael Wafula did not die from the impact of the vehicle that struck him. He died from what came after: 30 calls, and not one of them reached anyone who could help. \n\nThe Sequence of Events: \n\n9:47 AM - The Impact:\nWafula was walking along a road in Machakos County when a vehicle struck him and drove away. He was left on the tarmac, his body broken, his breathing shallow, and his consciousness slipping in and out. A passing motorist noticed him, checked his pulse and breathing, and took out his phone to start looking for help.\n\n9:51 AM - The First Call:\nA crowd gathered. Together with other motorists, they called the nearest public hospital. The line connected and rang. Nobody answered. They tried again. Same result.\n\n9:58 AM - The Second Call:\nThey tried a different facility. A line connected, and a voice told them the hospital had no ambulance available, and that they should try another number. They asked for it, wrote it down, and called. It rang out. No response.\n\n10:20 AM - The Emergency Line:\nThey found the county emergency line listed on a government website and called it. It did not connect. They called the national emergency toll-free numbers\u2014999, 112, and 911\u2014used to reach police, fire, or ambulance services countrywide. No one answered.\n\n12:00 PM - More Numbers:\nOne call finally connected to a private ambulance service. When the caller explained his location and the nature of the accident, he was asked to pay a down payment of Sh300,000 before an ambulance would be dispatched and a bed secured. He did not have the money.\n\n2:30 PM - His Breathing Changed:\nFive hours had passed. Wafula''s breathing became labored. They were still trying to reach family members who were now on their way. A school bus driver agreed to take him to the nearest hospital.\n\n3:07 PM - The Breathing Stopped:\nWafula died on the way to the hospital, surrounded by strangers who had volunteered to rush him there.\n\n\ud83d\uded1 STUDENT ACTION REQUIRED\n1. Analysis of System Failure:\n\nYour Response: (fill in)\n\ntext\nWhat were the failures in this case? ______________________________________\n1. _______________________________________________________________________\n2. _______________________________________________________________________\n3. _______________________________________________________________________\n4. _______________________________________________________________________\n\nWhat should the family/community have been able to access? ________________\n__________________________________________________________________________\n2. Recommendations:\n\nYour Response: (fill in)\n\ntext\nWhat systems need to be in place to prevent this? _________________________\n__________________________________________________________________________\n__________________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nAnalysis\tSystem Failures\t20\tIdentification of all system failures\nAnalysis\tRecommendations\t20\tPractical, evidence-based solutions\nReflection\tLessons Learned\t10\tInsightful understanding of issues\nTOTAL\t\t50", "sourceHeading": "CASE STUDY 9: MICHAEL WAFULA - 5 HOURS, NO AMBULANCE", "locationLine": "Machakos County - April 2026", "incidentStatistics": [], "phases": [{"phase": "Analysis", "body": "1. Analysis of System Failure:\n\nYour Response: (fill in)\n\ntext\nWhat were the failures in this case? ______________________________________\n1. _______________________________________________________________________\n2. _______________________________________________________________________\n3. _______________________________________________________________________\n4. _______________________________________________________________________\n\nWhat should the family/community have been able to access? ________________\n__________________________________________________________________________\n2. Recommendations:\n\nYour Response: (fill in)\n\ntext\nWhat systems need to be in place to prevent this? _________________________\n__________________________________________________________________________\n__________________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Analysis", "component": "System Failures", "points": 20, "criteria": "Identification of all system failures"}, {"phase": "Analysis", "component": "Recommendations", "points": 20, "criteria": "Practical, evidence-based solutions"}, {"phase": "Reflection", "component": "Lessons Learned", "points": 10, "criteria": "Insightful understanding of issues"}], "competencies": ["Scene Safety", "Communication"]}'::jsonb, 9, 70, true)
