INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('4c64527e-bbbf-5a76-b968-afc00cf2450f', 'WESTLANDS BUILDING COLLAPSE', 'Westlands, Nairobi', 'March 18, 2026', 'Structural Collapse Rescue', 'intermediate', 'On March 18, 2026, at approximately 7:30 PM, a building under construction partially collapsed in Westlands, Nairobi.', '{"rawText": "CASE STUDY 10: WESTLANDS BUILDING COLLAPSE\nWestlands, Nairobi - March 18, 2026\nIncident Background\nOn March 18, 2026, at approximately 7:30 PM, a building under construction partially collapsed in Westlands, Nairobi. \n\nIncident Statistics:\n\n1 fatality (Vincent Mokaya, assistant crane operator)\n\n1 injured rescued\n\n2 escaped unhurt\n\nTotal trapped: 4 workers\n\nBuilding height: 22 floors when collapse occurred\n\nTime of collapse: Around 8 PM\n\nThe Response:\nThe National Disaster Management Unit (NDMU) responded along with multiple agencies. The response operation was called off at about 3:30 AM on March 19, after successfully accounting for all persons. \n\nImmediate Context:\nThis was the latest such incident in the construction industry. Hours earlier, a building under construction collapsed in Chebocho Sub-location, Kericho County, leaving one person dead and several others injured. \n\nThe Kericho incident triggered a multi-agency emergency response involving Kenya Red Cross, National Government Administrative Officers, and local rescue teams. Four people were successfully rescued and rushed to Kericho County Referral Hospital. \n\n\ud83d\uded1 STUDENT ACTION REQUIRED\n1. Night Rescue Operations:\n\nYour Response: (fill in)\n\ntext\nWhat are the special challenges of a night rescue operation? ______________\n__________________________________________________________________________\n\nWhat additional safety considerations apply? ______________________________\n__________________________________________________________________________\n2. Worker Safety:\n\nYour Response: (fill in)\n\ntext\nWhat worker safety issues does this incident highlight? ___________________\n__________________________________________________________________________\n__________________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nAnalysis\tNight Operations\t15\tUnderstanding of night rescue challenges\nAnalysis\tWorker Safety\t15\tIdentification of safety issues\nReflection\tSystem Gaps\t10\tInsightful analysis of systemic issues\nTOTAL\t\t40", "sourceHeading": "CASE STUDY 10: WESTLANDS BUILDING COLLAPSE", "locationLine": "Westlands, Nairobi - March 18, 2026", "incidentStatistics": ["1 fatality (Vincent Mokaya, assistant crane operator)", "1 injured rescued", "2 escaped unhurt", "Total trapped: 4 workers", "Building height: 22 floors when collapse occurred", "Time of collapse: Around 8 PM"], "phases": [{"phase": "Analysis", "body": "1. Night Rescue Operations:\n\nYour Response: (fill in)\n\ntext\nWhat are the special challenges of a night rescue operation? ______________\n__________________________________________________________________________\n\nWhat additional safety considerations apply? ______________________________\n__________________________________________________________________________\n2. Worker Safety:\n\nYour Response: (fill in)\n\ntext\nWhat worker safety issues does this incident highlight? ___________________\n__________________________________________________________________________\n__________________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Analysis", "component": "Night Operations", "points": 15, "criteria": "Understanding of night rescue challenges"}, {"phase": "Analysis", "component": "Worker Safety", "points": 15, "criteria": "Identification of safety issues"}, {"phase": "Reflection", "component": "System Gaps", "points": 10, "criteria": "Insightful analysis of systemic issues"}], "competencies": ["Scene Safety", "Trauma", "Communication"]}'::jsonb, 10, 70, true)
