INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('cb4a9408-caf7-505e-807e-f476a67921c7', 'NAIROBI PROTESTS MEDICAL RESPONSE', 'Nairobi', 'July 2024', 'Civil Unrest Medical Response', 'advanced', 'During the 2024 protests in Nairobi, Médecins Sans Frontières/Doctors Without Borders (MSF) contributed to the emergency response efforts.', '{"rawText": "CASE STUDY 11: NAIROBI PROTESTS MEDICAL RESPONSE\nNairobi - July 2024\nIncident Background\nDuring the 2024 protests in Nairobi, M\u00e9decins Sans Fronti\u00e8res/Doctors Without Borders (MSF) contributed to the emergency response efforts. \n\nThe Response: \n\nAbbas Bahola, an Emergency Supervisor with MSF, described the response:\n\n\"For the recent protests, we made plans to dispatch our ambulance and medical team, we made sure we had additional staff ready to respond to an influx of patients, and arranged referral possibilities in place for people who need more advanced medical care.\"\n\nMedical Setup:\n\nAmbulances went to the Central Business District (CBD) to join other actors\n\nMedical post was set up by the Nairobi Emergency Operating Coordination Centre (EOC) at Jamia Mosque\n\nLater shifted to Holy Family Basilica\n\nTypes of Injuries:\n\"Most of the patients we had seen had fractures, wounds, soft tissue injuries, and a few gunshot wounds, both from rubber and live bullets.\" \n\nChallenges:\n\nAccess to medical sites became complicated\n\nAn ambulance was attacked by rowdy crowds while transporting patients\n\nStaff were shaken, one staff got physically injured\n\nDelay in care of patients on board\n\nRole of MSF:\n\"We treat and discharge those with less severe injuries. For more severe cases, we stabilize the patients and refer them in our ambulances to Mama Lucy hospital or Kenyatta National Hospital.\" \n\nMSF triaged 71 patients in the first two days. \n\n\ud83d\uded1 STUDENT ACTION REQUIRED\n1. Protest Response Planning:\n\nYour Response: (fill in)\n\ntext\nWhat are the challenges of providing medical care during protests? ________\n__________________________________________________________________________\n\nWhat are the types of injuries expected? _________________________________\n__________________________________________________________________________\n\nHow does the triage differ? _______________________________________________\n2. Ambulance Safety:\n\nYour Response: (fill in)\n\ntext\nWhat happens when an ambulance is attacked? _______________________________\n__________________________________________________________________________\n\nWhat safety measures should be in place? __________________________________\n__________________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nAnalysis\tProtest Response\t15\tUnderstanding of protest medical response\nAnalysis\tInjury Patterns\t10\tIdentification of expected injuries\nAnalysis\tAmbulance Safety\t15\tUnderstanding of safety measures\nReflection\tLessons Learned\t10\tInsightful analysis of challenges\nTOTAL\t\t50", "sourceHeading": "CASE STUDY 11: NAIROBI PROTESTS MEDICAL RESPONSE", "locationLine": "Nairobi - July 2024", "incidentStatistics": [], "phases": [{"phase": "Analysis", "body": "1. Protest Response Planning:\n\nYour Response: (fill in)\n\ntext\nWhat are the challenges of providing medical care during protests? ________\n__________________________________________________________________________\n\nWhat are the types of injuries expected? _________________________________\n__________________________________________________________________________\n\nHow does the triage differ? _______________________________________________\n2. Ambulance Safety:\n\nYour Response: (fill in)\n\ntext\nWhat happens when an ambulance is attacked? _______________________________\n__________________________________________________________________________\n\nWhat safety measures should be in place? __________________________________\n__________________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Analysis", "component": "Protest Response", "points": 15, "criteria": "Understanding of protest medical response"}, {"phase": "Analysis", "component": "Injury Patterns", "points": 10, "criteria": "Identification of expected injuries"}, {"phase": "Analysis", "component": "Ambulance Safety", "points": 15, "criteria": "Understanding of safety measures"}, {"phase": "Reflection", "component": "Lessons Learned", "points": 10, "criteria": "Insightful analysis of challenges"}], "competencies": ["Scene Safety", "Trauma", "Communication", "EMS Operations"]}'::jsonb, 11, 70, true)
