INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('855e7782-6789-5aa2-a72c-282b1e4a9622', 'RAILA ODINGA''S BODY RECEPTION - MEDICAL COVERAGE', 'JKIA, Nairobi', 'October 16, 2025', 'Mass Gathering Medical Coverage', 'intermediate', 'On October 16, 2025, the Ministry of Health deployed 36 ambulances to provide emergency medical coverage during the arrival and reception of the body of the late Hon. Raila Amolo Odinga at Jomo Kenyatta International Airport (JKIA).', '{"rawText": "CASE STUDY 12: RAILA ODINGA''S BODY RECEPTION - MEDICAL COVERAGE\nJKIA, Nairobi - October 16, 2025\nIncident Background\nOn October 16, 2025, the Ministry of Health deployed 36 ambulances to provide emergency medical coverage during the arrival and reception of the body of the late Hon. Raila Amolo Odinga at Jomo Kenyatta International Airport (JKIA). \n\nThe Deployment: \n\nThe Principal Secretary for Medical Services Ouma Oluga said the deployment would ensure rapid medical response and safety for thousands of mourners expected to gather at the airport and along major routes in Nairobi.\n\nAmbulance Specifications:\n\nEach ambulance fully equipped with Basic Life Support (BLS) and Advanced Life Support (ALS) facilities\n\nStaffed with a paramedic, nurse, and driver\n\nAimed to provide immediate treatment and facilitate safe evacuation\n\nResources Mobilized:\n\nKenya Red Cross\n\nSt. John Ambulance\n\nNairobi Disaster Service\n\nNairobi Emergency Services\n\nKenyatta National Hospital\n\nPort Health ambulance on standby at JKIA\n\nExtended Coverage:\nMobilization efforts were ongoing to extend full emergency medical coverage to Kisumu and Siaya Counties, where national mourning activities were expected to continue. \n\n\ud83d\uded1 STUDENT ACTION REQUIRED\n1. Mass Gathering Medical Planning:\n\nYour Response: (fill in)\n\ntext\nWhat are the key considerations for medical coverage at a mass gathering?\n__________________________________________________________________________\n\nWhat types of medical emergencies are expected at a large public event?\n__________________________________________________________________________\n\nHow do you coordinate multiple agencies for medical coverage? _____________\n__________________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nAnalysis\tMass Gathering\t15\tUnderstanding of mass gathering medical planning\nAnalysis\tResource Coordination\t15\tUnderstanding of multi-agency coordination\nReflection\tEvent Medical Needs\t10\tIdentification of expected emergencies\nTOTAL\t\t40", "sourceHeading": "CASE STUDY 12: RAILA ODINGA''S BODY RECEPTION - MEDICAL COVERAGE", "locationLine": "JKIA, Nairobi - October 16, 2025", "incidentStatistics": [], "phases": [{"phase": "Analysis", "body": "1. Mass Gathering Medical Planning:\n\nYour Response: (fill in)\n\ntext\nWhat are the key considerations for medical coverage at a mass gathering?\n__________________________________________________________________________\n\nWhat types of medical emergencies are expected at a large public event?\n__________________________________________________________________________\n\nHow do you coordinate multiple agencies for medical coverage? _____________\n__________________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Analysis", "component": "Mass Gathering", "points": 15, "criteria": "Understanding of mass gathering medical planning"}, {"phase": "Analysis", "component": "Resource Coordination", "points": 15, "criteria": "Understanding of multi-agency coordination"}, {"phase": "Reflection", "component": "Event Medical Needs", "points": 10, "criteria": "Identification of expected emergencies"}], "competencies": ["Scene Safety", "Communication", "EMS Operations"]}'::jsonb, 12, 70, true)
