INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('dc6ce645-5e5b-533e-9ccb-5be6d1242a33', 'ST GABRIEL ISONGO SECONDARY SCHOOL - PARENT INVASION', 'Mumias East, Kakamega County', 'January 15, 2024', 'School Civil Unrest Response', 'intermediate', 'On January 15, 2024, angry parents stormed St Gabriel Isongo Secondary School in Mumias East, Kakamega County, to protest and eject the principal from his office over alleged poor performance in the 2023 KCSE examination.', '{"rawText": "CASE STUDY 13: ST GABRIEL ISONGO SECONDARY SCHOOL - PARENT INVASION\nMumias East, Kakamega County - January 15, 2024\nIncident Background\nOn January 15, 2024, angry parents stormed St Gabriel Isongo Secondary School in Mumias East, Kakamega County, to protest and eject the principal from his office over alleged poor performance in the 2023 KCSE examination. \n\nThe Incident: \n\nAngry parents and students breached security and went straight to the principal''s office before frog-marching him out of the school''s compound.\n\nThe Accusations:\n\nAccused principal of failing to uplift the school''s academic standards\n\nAlleged lack of commitment\n\nSchool''s mean score had dropped from 5 to 2 under the principal''s leadership\n\nThe Aftermath: \n\nTSC transferred 17 teachers to other institutions within Bungoma and Kakamega counties. Only 8 teachers - employed by the Board of Management - were left to manage the school.\n\nKUPPET officials urged teachers not to resume work until security was addressed. Kakamega branch chairman Johnstone Wabuti questioned why none of the suspects had been apprehended. \n\nGovernment Response:\nEducation Cabinet Secretary Ezekiel Machogu warned: \"Going forward, the Ministry of Education will treat any invasion to schools to frog-march teachers out of their workstations as acts of crime that will prompt firm and decisive action from law enforcers.\" \n\n\ud83d\uded1 STUDENT ACTION REQUIRED\n1. School Emergency Response:\n\nYour Response: (fill in)\n\ntext\nWhat are the challenges when a school becomes a scene of civil unrest? ____\n__________________________________________________________________________\n\nWhat is the role of EMS in a school invasion incident? ____________________\n__________________________________________________________________________\n\nHow do you coordinate with police and other agencies? _____________________\n__________________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nAnalysis\tScene Assessment\t15\tUnderstanding of school unrest challenges\nAnalysis\tEMS Role\t15\tAppropriate identification of EMS responsibilities\nReflection\tSystem Gaps\t10\tInsightful analysis of issues\nTOTAL\t\t40", "sourceHeading": "CASE STUDY 13: ST GABRIEL ISONGO SECONDARY SCHOOL - PARENT INVASION", "locationLine": "Mumias East, Kakamega County - January 15, 2024", "incidentStatistics": [], "phases": [{"phase": "Analysis", "body": "1. School Emergency Response:\n\nYour Response: (fill in)\n\ntext\nWhat are the challenges when a school becomes a scene of civil unrest? ____\n__________________________________________________________________________\n\nWhat is the role of EMS in a school invasion incident? ____________________\n__________________________________________________________________________\n\nHow do you coordinate with police and other agencies? _____________________\n__________________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Analysis", "component": "Scene Assessment", "points": 15, "criteria": "Understanding of school unrest challenges"}, {"phase": "Analysis", "component": "EMS Role", "points": 15, "criteria": "Appropriate identification of EMS responsibilities"}, {"phase": "Reflection", "component": "System Gaps", "points": 10, "criteria": "Insightful analysis of issues"}], "competencies": ["Scene Safety", "Communication", "EMS Operations"]}'::jsonb, 13, 70, true)
