INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('32375b40-5a58-54fd-875b-db2078c345d3', 'NATIONAL EMS SYSTEM GAPS - AUDITOR GENERAL''S REPORT', 'Nationwide', '2021/22 to 2024/25', 'EMS System Audit', 'advanced', 'The Auditor General''s report, released in 2026, cited serious gaps in emergency medical care covering ambulance services, hospital emergency care, and public awareness of pre-hospital emergency services.', '{"rawText": "CASE STUDY 14: NATIONAL EMS SYSTEM GAPS - AUDITOR GENERAL''S REPORT\nNationwide - 2021/22 to 2024/25\nBackground\nThe Auditor General''s report, released in 2026, cited serious gaps in emergency medical care covering ambulance services, hospital emergency care, and public awareness of pre-hospital emergency services. \n\nKey Findings: \n\nAmbulance Availability:\n\"Vehicles recorded in government asset registers as operational ambulances are non-functional, grounded by mechanical failure, lacking fuel, or missing critical equipment. In some cases, ambulances have been found to have been out of service for months or years without repair or replacement.\"\n\nResponse Times:\nThe internationally accepted standard is 15-20 minutes. The audit found delays ranging from 20 minutes to a full hour.\n\nAmbulance Equipment:\nAmbulances that were empty, carrying no equipment at all.\n\nEmergency Lines:\nCalls in several instances not connecting to any operational dispatch function.\n\nCounty Shortfalls:\n\nNairobi County: 20 of 50 required ambulances; response times 20-60 minutes\n\nMombasa: Response times up to 60 minutes\n\nKisii County: Worst response times alongside Mombasa\n\nWHO Standard:\nOne ambulance per 70,000 to 100,000 people.\n\nThe Policy Gap: \n\n\"The Kenya Emergency Medical Care Policy 2020 to 2030 was signed and gazetted. It exists. It identifies the right priorities, calls for the right investments, and maps the right interventions. But a policy document is not a working ambulance. Whether it is being implemented with the consistency, funding, and accountability it requires is another matter entirely.\" \n\n\ud83d\uded1 STUDENT ACTION REQUIRED\n1. System Gap Analysis:\n\nYour Response: (fill in)\n\ntext\nWhat are the THREE most critical gaps in Kenya''s EMS system?\n1. _______________________________________________________________________\n2. _______________________________________________________________________\n3. _______________________________________________________________________\n\nHow do these gaps affect patient outcomes? ________________________________\n__________________________________________________________________________\n2. Recommendations:\n\nYour Response: (fill in)\n\ntext\nWhat immediate improvements are needed? ___________________________________\n__________________________________________________________________________\n\nWhat long-term reforms are needed? ________________________________________\n__________________________________________________________________________\n\ud83d\udcca EVALUATION SCORING\nSection\tComponent\tPoints\tCriteria\nAnalysis\tSystem Gaps\t20\tCorrect identification of critical gaps\nAnalysis\tImpact Analysis\t15\tUnderstanding of patient impact\nReflection\tRecommendations\t15\tPractical, evidence-based solutions\nTOTAL\t\t50", "sourceHeading": "CASE STUDY 14: NATIONAL EMS SYSTEM GAPS - AUDITOR GENERAL''S REPORT", "locationLine": "Nationwide - 2021/22 to 2024/25", "incidentStatistics": [], "phases": [{"phase": "Analysis", "body": "1. System Gap Analysis:\n\nYour Response: (fill in)\n\ntext\nWhat are the THREE most critical gaps in Kenya''s EMS system?\n1. _______________________________________________________________________\n2. _______________________________________________________________________\n3. _______________________________________________________________________\n\nHow do these gaps affect patient outcomes? ________________________________\n__________________________________________________________________________\n2. Recommendations:\n\nYour Response: (fill in)\n\ntext\nWhat immediate improvements are needed? ___________________________________\n__________________________________________________________________________\n\nWhat long-term reforms are needed? ________________________________________\n__________________________________________________________________________\n\ud83d\udcca"}], "evaluation": [{"phase": "Analysis", "component": "System Gaps", "points": 20, "criteria": "Correct identification of critical gaps"}, {"phase": "Analysis", "component": "Impact Analysis", "points": 15, "criteria": "Understanding of patient impact"}, {"phase": "Reflection", "component": "Recommendations", "points": 15, "criteria": "Practical, evidence-based solutions"}], "competencies": ["Scene Safety", "Communication", "EMS Operations"]}'::jsonb, 14, 70, true)
