INSERT INTO case_studies (id, title, location, incident_date, category, difficulty, description, content, order_number, passing_percentage, is_active)
VALUES ('cd21f673-2109-5244-b1aa-813b7de31459', 'THE STATE OF EMERGENCY CARE - SYSTEM FAILURES', 'Kenya', 'Module Reflection', 'Emergency Care Systems Review', 'advanced', '', '{"rawText": "CASE STUDY 15: THE STATE OF EMERGENCY CARE - SYSTEM FAILURES\nSummary of Critical Issues\nBased on all case studies, the following systemic issues have been identified:\n\nAmbulance Shortage: Nairobi County has only 20 of the 50 ambulances required \n\nResponse Time Failures: Delays ranging from 20 minutes to over 5 hours \n\nEquipment Gaps: Ambulances \"empty, carrying no equipment at all\" \n\nEmergency Line Failures: 999, 112, and 911 calls not connecting \n\nPrivate Ambulance Barriers: Sh300,000 down payment required \n\nHospital Overload: Kenyatta National Hospital queue delays causing deaths \n\nSchool Safety Failures: Locked dormitory doors, corporal punishment, fire safety gaps\n\nBuilding Regulation Failures: Substandard materials, structural violations\n\n\ud83d\uded1 FINAL REFLECTION\nYour Response: (fill in)\n\ntext\nWhat are the THREE most important lessons you have learned from these case studies?\n\n1. _______________________________________________________________________\n\n2. _______________________________________________________________________\n\n3. _______________________________________________________________________\n\nHow will this affect your practice as an EMT? ____________________________\n__________________________________________________________________________\n\nWhat will you do to advocate for system improvement? ______________________\n__________________________________________________________________________\nFINAL CERTIFICATION CHECK\nCore Competencies Assessed Across All Case Studies\nCompetency\tCase Studies\tKey Actions\nScene Safety\tAll\tCorrect identification of hazards, scene approach, PPE\nTriage\t1,2,3,4,6,8\tCorrect START triage classification, prioritization\nAirway Management\tAll\tAirway assessment, BVM use, suctioning\nBreathing Assessment\tAll\tRR, depth, O2 administration, ventilatory support\nCirculation Assessment\tAll\tPulse, BP, skin assessment, bleeding control\nPatient Assessment\tAll\tInitial, focused, and on-going assessment\nCommunication\tAll\tRadio report, hospital notification, documentation\nEMS Operations\tAll\tIncident command, resource coordination\nMedical Emergencies\tAll\tRecognition and management of medical conditions\nTrauma Emergencies\tAll\tRecognition and management of traumatic injuries\nPediatric Emergencies\t2,3\tRecognition and management of pediatric patients\nMass Casualty\t1,2,3,4,6\tMCI management, triage, resource allocation\nCrush Injury Management\t5,7,10\tRecognition and management of crush injuries\nSystem Advocacy\t9,14,15\tUnderstanding of EMS system gaps and solutions\n\ud83d\udccb FINAL SCORING SUMMARY\nCase Study\tPoints Available\tPoints Earned\tPercentage\tPass/Fail\n1. DusitD2 Terror Attack\t80\t\t\t\n2. Utumishi Girls Academy Fire\t80\t\t\t\n3. Kakamega Primary School Stampede\t80\t\t\t\n4. Nairobi Bus MCI\t70\t\t\t\n5. Kisumu Building Collapse\t80\t\t\t\n6. Kakamega Funeral Bus Crash\t70\t\t\t\n7. Karen Building Collapse\t65\t\t\t\n8. JKIA Emergency Incidents\t50\t\t\t\n9. Michael Wafula - System Failure\t50\t\t\t\n10. Westlands Building Collapse\t40\t\t\t\n11. Nairobi Protests\t50\t\t\t\n12. Raila Odinga Body Reception\t40\t\t\t\n13. St Gabriel Isongo School Invasion\t40\t\t\t\n14. Auditor General''s Report\t50\t\t\t\n15. System Failures - Final Reflection\t50\t\t\t\nTOTAL\t895\t\t\t\nFINAL PASSING REQUIREMENT: 70% overall (627/895 points)\n\nEach individual case study must achieve \u226570% to pass the module.", "sourceHeading": "CASE STUDY 15: THE STATE OF EMERGENCY CARE - SYSTEM FAILURES", "locationLine": "Kenya - Module Reflection", "incidentStatistics": [], "phases": [{"phase": "Reflection", "body": "FINAL REFLECTION\nYour Response: (fill in)\n\ntext\nWhat are the THREE most important lessons you have learned from these case studies?\n\n1. _______________________________________________________________________\n\n2. _______________________________________________________________________\n\n3. _______________________________________________________________________\n\nHow will this affect your practice as an EMT? ____________________________\n__________________________________________________________________________\n\nWhat will you do to advocate for system improvement? ______________________\n__________________________________________________________________________"}], "evaluation": [{"phase": "Reflection", "component": "Lessons Learned", "points": 20, "criteria": "Identify the most important lessons from the case module."}, {"phase": "Reflection", "component": "Practice Impact", "points": 15, "criteria": "Explain how the case module changes your EMT practice."}, {"phase": "Reflection", "component": "System Advocacy", "points": 15, "criteria": "Describe how you will advocate for emergency care system improvement."}], "competencies": ["Scene Safety", "Communication", "EMS Operations"]}'::jsonb, 15, 70, true)
